 const fields = $json.data?.card?.fields || [];
 const action = $('Tarefa/projeto criada/atualizada').item.json.body.data.action;

 // Determine which field to search for based on action
 let fieldToSearch = "projeto_associado";

 if (action === "card.create") {
   fieldToSearch = "id_do_projeto_associado";
 }

 // First, try to find the determined field and get its array_value[0]
 const projetoAssociado = fields.find(x => (x.field?.id || x.indexName || "") === fieldToSearch);

 if (projetoAssociado?.array_value?.[0] != null) {
   const value = String(projetoAssociado.array_value[0]).trim();
   // Check if it's an empty array string
   if (value !== "" && value !== "[]") {
     return value;
   }
 }

 // If not found or array_value doesn't exist, look for the same field's value property
 const idProjeto = fields.find(x => (x.field?.id || x.indexName || "") === fieldToSearch);

 if (idProjeto?.value != null) {
   const value = String(idProjeto.value).trim();
   // Check if it's an empty array string
   if (value !== "" && value !== "[]") {
     return value;
   }
 }

 // If neither is found or both are empty/[], return empty string
 return "";
})()
}}

