  // Substitui a lógica de "projeto" por "tarefa principal"
  const fieldToSearch = "id_da_tarefa_principal";

  const field = fields.find(f => (f.field?.id || f.indexName || "") === fieldToSearch);

  const normalize = (v) => {
    if (v == null) return "";
    const s = String(v).trim();
    return (s !== "" && s !== "[]") ? s : "";
  };

  // Prioriza array_value[0] (quando existir), senão cai no value
  return normalize(field?.array_value?.[0]) || normalize(field?.value) || "";
})()
}}

