(() => {
  const pipeId = $('Pegar informação do card').item.json.data.card.pipe.id;
  const dados = $('Dados do card').item.json;

  const hasValue = (v) => v !== null && v !== undefined && String(v).trim() !== '';

  const hasProjeto = hasValue(dados.idProjetoAssociado);
  const hasTarefa  = hasValue(dados.idTarefaPrincipal); // ✅ apenas este campo

  const TAG_SUBTAREFA = '317187179';

  const tagProjeto =
    pipeId == 306877425 ? '317083825' :
    pipeId == 306877345 ? '317083521' :
    '';

  let tagPrioridade = '';

  if (pipeId == 306877425) {
    tagPrioridade =
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Baixo' ? '317083822' :
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Médio' ? '317083821' :
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Alto'  ? '317083820' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Baixo' ? '317083823' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Médio' ? '317083822' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Alto'  ? '317083821' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Baixo' ? '317083824' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Médio' ? '317083823' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Alto'  ? '317083822' :
      '';
  } else if (pipeId == 306877345) {
    tagPrioridade =
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Baixo' ? '317083529' :
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Médio' ? '317083526' :
      dados.esforcoEstimado === 'Baixo' && dados.retornoEstimado === 'Alto'  ? '317083521' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Baixo' ? '317083530' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Médio' ? '317083529' :
      dados.esforcoEstimado === 'Médio' && dados.retornoEstimado === 'Alto'  ? '317083526' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Baixo' ? '317083541' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Médio' ? '317083530' :
      dados.esforcoEstimado === 'Alto'  && dados.retornoEstimado === 'Alto'  ? '317083529' :
      '';
  }

  // fallback (só relevante nos cenários que usam prioridade)
  if (!hasValue(tagPrioridade)) {
    tagPrioridade =
      pipeId == 306877425 ? '317083822' :
      pipeId == 306877345 ? '317083529' :
      '';
  }

  // Regras
  let tags = [];
  const hasTagProjeto = hasProjeto && hasValue(tagProjeto);

  if (hasTagProjeto) {
    // projeto -> só projeto | projeto + tarefa -> projeto + subtarefa
    tags = hasTarefa ? [tagProjeto, TAG_SUBTAREFA] : [tagProjeto];
  } else if (hasTarefa) {
    // sem projeto + tarefa -> subtarefa + prioridade
    tags = [TAG_SUBTAREFA, tagPrioridade];
  } else {
    // sem projeto e sem tarefa -> só prioridade
    tags = [tagPrioridade];
  }

  return Array.from(new Set(tags.filter(hasValue))).slice(0, 3);
})()
}}

