const prioridade = $input.item.json.prioridade;
const categoriaIdRaw = $input.item.json.categoriaId; // ✅ agora normalmente vem como array (ex.: ["id1","id2"])
const cardId = $('Dados do card').item.json.cardId;
const idProjetoAssociado = $('Dados do card').item.json.idProjetoAssociado;
const action = $('Tarefa/projeto criada/atualizada').item.json.body.data.action;

const hasValue = (v) => v !== null && v !== undefined && String(v).trim() !== '';

const includePrioridade =
  hasValue(prioridade) &&
  Number(prioridade) >= 0 &&
  Number(prioridade) <= 100;

const isCardCreate = action === "card.create";

const hasProjetoAssociado =
  idProjetoAssociado !== undefined &&
  idProjetoAssociado !== null &&
  (typeof idProjetoAssociado !== "string" || idProjetoAssociado.trim() !== "");

// Normaliza para array SEMPRE, priorizando o novo formato (array)
const normalizeCategoriaIds = (raw) => {
  if (raw === null || raw === undefined) return [];

  // ✅ novo formato esperado
  if (Array.isArray(raw)) return raw;

  const s = String(raw).trim();
  if (s === "" || s === "[]") return [];

  // cobre string exibida às vezes como: [Array: ["a","b"]]
  if (s.startsWith("[Array:")) {
    const start = s.indexOf("[", 7);
    const end = s.lastIndexOf("]");
    if (start !== -1 && end !== -1 && end > start) {
      const inner = s.slice(start, end + 1);
      try {
        const parsed = JSON.parse(inner);
        if (Array.isArray(parsed)) return parsed;
      } catch (e) {}
    }
  }

  // JSON array em string: '["a","b"]'
  if (s.startsWith("[") && s.endsWith("]")) {
    try {
      const parsed = JSON.parse(s);
      if (Array.isArray(parsed)) return parsed;
    } catch (e) {}
  }

  // string no formato `"a","b"` ou `a,b` ou `"a"`
  return s
    .replace(/^\[|\]$/g, "")
    .split(",")
    .map(v => v.trim())
    .filter(v => v !== "");
};

// Converte array -> literal GraphQL: `"a","b"`
const buildCategoriaListLiteral = (raw) => {
  const ids = normalizeCategoriaIds(raw)
    .map(v => String(v).trim())
    .filter(v => v !== "" && v !== "[]")
    .map(v => v.replace(/^"|"$/g, "")); // remove aspas externas se vierem

  const unique = Array.from(new Set(ids)).slice(0, 3); // segurança extra

  return unique.map(v => `"${v}"`).join(",");
};

const categoriaListLiteral = buildCategoriaListLiteral(categoriaIdRaw);

let mutation = `mutation UpdateCardFields($cardId: ID!) {`;

if (includePrioridade) {
  mutation += `
  updateCardField(input: {card_id: $cardId field_id: "prioridade" new_value: "${Number(prioridade)}"}) {
    card {id}
    success
  }`;
}

mutation += `
  updateCardField2: updateCardField(input: {card_id: $cardId field_id: "categoria_de_prioridade" new_value: [${categoriaListLiteral}]}) {
    card {id}
    success
  }`;

if (isCardCreate && hasProjetoAssociado) {
  mutation += `
  updateCardField3: updateCardField(input: {card_id: $cardId field_id: "projeto_associado" new_value: "${idProjetoAssociado}"}) {
    card {id}
    success
  }`;
}

mutation += `
}`;

const queryVariables = { cardId };

return {
  query: mutation,
  queryVariables,
};
